def amicable_numbers_sum(n):
    def is_amicable(a):
        b = sum([i for i in range(1, a) if a % i == 0])
        return a != b and sum([i for i in range(1, b) if b % i == 0]) == a

    return sum([i for i in range(1, n) if is_amicable(i)])

# Example usage:
print(amicable_numbers_sum(10000))  # Output: 31626
```

