def is_majority(arr, n, x):
    # Initialize the count of the element
    count = 0

    # Iterate through the array to count occurrences of the element
    for i in range(n):
        if arr[i] == x:
            count += 1

    # Check if the count is greater than n/2
    if count > n // 2:
        return True
    else:
        return False
```

