def geometric_sum(n):
    # Base case: if n is 0, return 1
    if n == 0:
        return 1
    # Recursive case: return 1/n plus the geometric sum of n-1
    else:
        return 1 / n + geometric_sum(n - 1)

# Example usage:
print(geometric_sum(3))  # Output: 1.8333333333333333
```

