```python
def convert_list_dictionary(*lists):
    if not lists:
        return {}

    # Start with the first list as the base dictionary
    result = {lists[0][i]: {} for i in range(len(lists[0]))}

    # Iterate over the remaining lists to populate the nested dictionary
    for i in range(1, len(lists)):
        current_level = result
        for j in range(len(lists[i])):
            if j == len(lists[i]) - 1:
                # If it's the last element, assign the value
                current_level[lists[i][j]] = lists[i + 1][j]
            else:
                # Otherwise, create a new dictionary for the next level
                current_level[lists[i][j]] = {}
                current_level = current_level[lists[i][j]]

    return result

