def convert_list_dictionary(list_of_lists):
    """
    Convert a list of lists into a nested dictionary.

    Args:
    list_of_lists (list of list): A list of lists to be converted.

    Returns:
    dict: A nested dictionary created from the input list of lists.
    """
    nested_dict = {}
    for sublist in list_of_lists:
        if not isinstance(sublist, list):
            raise ValueError("All elements in the list must be lists.")
        for key, value in sublist.items():
            if not isinstance(key, str):
                raise ValueError("All keys in the list must be strings.")
            if not isinstance(value, (int, float)):
                raise ValueError("All values in the list must be numbers.")
            nested_dict[key] = value
    return nested_dict
```

