```python
def reverse_vowels(s):
    vowels = "aeiouAEIOU"
    s = list(s)
    left, right = 0, len(s) - 1

    while left < right:
        if s[left] not in vowels:
            left += 1
        elif s[right] not in vowels:
            right -= 1
        else:
            s[left], s[right] = s[right], s[left]
            left += 1
            right -= 1

    return ''.join(s)
```

```python
def sequence(n):
    if n == 1 or n == 2:
        return 1
    else:
        sequence = [1, 1]
        for i in range(2, n):
            sequence.append(sequence[sequence[i - 1] - 1] + sequence[i - sequence[i - 1]])
        return sequence[n - 1]
```

```python
def is_decimal(s):
    # Check if the string is empty
    if not s:
        return False

    # Check if the string is a valid decimal number with a precision of 2
    try:
        # Convert the string to a float and check if it has exactly 2 decimal places
        float_value = float(s)
        return float_value.is_integer() or (float_value - int(float_value)) == 0.01
    except ValueError:
        return False
```

